INSERT INTO public.drugsafe_user (
                                     user_id
                                   , user_login_id
                                   , user_pw
                                   , user_name
                                   , user_email
                                   , user_tel
                                   , gender_type_cd
                                   , user_status_cd
                                   , mbsh_se_cd
                                   , user_type_cd
                                   , last_ip
                                   , del_yn
                                   , in_admin_id
                                   , in_datetime
                            ) VALUES (
                                   #{userId}
                                 , #{userLoginId}
                                 , #{userPw}
                                 , #{userName}
                                 , #{userEmail}
                                 , safe_encrypt(#{userTel},'${db_encrypt_key}')
                                 , #{genderTypeCd}
                                 , #{userStatusCd}
                                 , #{mbshSeCd}
                                 , #{userTypeCd}
                                 , #{lastIp}
                                 , #{delYn}
                                 , #{inAdminId}
                                 , NOW() -- 등록 일시
                                 );
